SELECT
FROM FCT.TB_CONFIG_INTERFACE_MST A
AND A.SOFFICECODE IN ( SELECT DISTINCT LVLR.SSVC_OBJ_CD FROM MST.TB_LVL_ROLE_SUB LVLR , MST.TB_LVL_SUB_CD LVLS , MST.TB_LVL_MST LVLM WHERE LVLR.SSVC_OFFICE_CD = LVLS.SLOFFICECODE AND LVLS.SLVL_CD = LVLM.SSVC_OBJ_CD AND LVLM.NLVL_MST_SEQ IN
#{item.nlvlSeq}
)
ORDER BY A.SHOST_NM, A.SIF_NM ASC

SELECT count(1) totalCount FROM FCT.TB_CONFIG_INTERFACE_MST A
AND A.SOFFICECODE IN ( SELECT DISTINCT LVLR.SSVC_OBJ_CD FROM MST.TB_LVL_ROLE_SUB LVLR , MST.TB_LVL_SUB_CD LVLS , MST.TB_LVL_MST LVLM WHERE LVLR.SSVC_OFFICE_CD = LVLS.SLOFFICECODE AND LVLS.SLVL_CD = LVLM.SSVC_OBJ_CD AND LVLM.NLVL_MST_SEQ IN
#{item.nlvlSeq}
)

SELECT DISTINCT A.SHOST_IP, A.SHOST_NM FROM FCT.TB_CONFIG_INTERFACE_MST A
AND A.SOFFICECODE IN ( SELECT DISTINCT LVLR.SSVC_OBJ_CD FROM MST.TB_LVL_ROLE_SUB LVLR , MST.TB_LVL_SUB_CD LVLS , MST.TB_LVL_MST LVLM WHERE LVLR.SSVC_OFFICE_CD = LVLS.SLOFFICECODE AND LVLS.SLVL_CD = LVLM.SSVC_OBJ_CD AND LVLM.NLVL_MST_SEQ IN
#{item.nlvlSeq}
)
ORDER BY A.SHOST_NM ASC

SELECT count(DISTINCT A.SHOST_IP) totalCount FROM FCT.TB_CONFIG_INTERFACE_MST A
AND A.SOFFICECODE IN ( SELECT DISTINCT LVLR.SSVC_OBJ_CD FROM MST.TB_LVL_ROLE_SUB LVLR , MST.TB_LVL_SUB_CD LVLS , MST.TB_LVL_MST LVLM WHERE LVLR.SSVC_OFFICE_CD = LVLS.SLOFFICECODE AND LVLS.SLVL_CD = LVLM.SSVC_OBJ_CD AND LVLM.NLVL_MST_SEQ IN
#{item.nlvlSeq}
)

SELECT 
	   , A.RNUM FROM (
	SELECT 
		   , ROWNUM RNUM FROM (
		SELECT


		FROM FCT.TB_CONFIG_INTERFACE_MST A




	) A WHERE ROWNUM <= #{lastIndex}
) A WHERE RNUM >= #{firstIndex}

SELECT
	count(1) totalCount
FROM FCT.TB_CONFIG_INTERFACE_MST A
WHERE A.SHOST_IP = #{shostIp, jdbcType=VARCHAR}
AND A.SIF_IP = #{sifIp, jdbcType=VARCHAR}
